function handleRootUrl (url) {
	if (url && !url.startsWith('/') && !url.includes('://')) {
		return url;
	}
	if (url && url.startsWith('/')) {
		if (sysRootUrl != "" && !url.startsWith(sysRootUrl)) {
			url = sysRootUrl + url;
		}
		return url; 
	}
	return url;
}






